def minPath(grid, k):
    """
    Find the minimum path of length k in a grid.
    """
    n = len(grid)

    # Helper function to check if a cell is within bounds
    def is_valid(x, y):
        return 0 <= x < n and 0 <= y < n

    # Use DFS to explore all possible paths of length k starting from each cell
    def dfs(x, y, path, remaining_steps):
        nonlocal min_path

        if remaining_steps == 0:
            if not min_path or path < min_path:
                min_path = path[:]
            return

        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if is_valid(nx, ny):
                dfs(nx, ny, path + [grid[nx][ny]], remaining_steps - 1)

    # Initialize the minimum path to a large value
    min_path = [n * n + 1] * k

    # Start DFS from each cell in the grid
    for i in range(n):
        for j in range(n):
            dfs(i, j, [grid[i][j]], k - 1)

    return min_path

