        for j in range(i, n // 3 + 1, 2):
            for k in range(j, n // 2 + 1, 2):
                l = n - (i + j + k)
                if l >= k and l % 2 == 0:
                    return True
    return False

def fix_spaces(text):
    new_text = ""
    i, count = 0, 0
    while i < len(text):
        if text[i] == " ":
            count += 1
        else:
            if count > 2:
                new_text += "-"
            else:
                new_text += "_" * count
            count = 0
            new_text += text[i]
        i += 1
    # Handle trailing spaces
    if count > 2:
        new_text += "-"
    else:
        new_text += "_" * count
    return new_text

