def compare(game, guess):
    """Compare guesses with actual game scores and return the absolute differences."""

    # Validate input types
    if not isinstance(game, list) or not all(isinstance(x, int) for x in game):
        raise ValueError("Game must be a list of integers.")
    if not isinstance(guess, list) or not all(isinstance(x, int) for x in guess):
        raise ValueError("Guess must be a list of integers.")

    # Validate that both lists are of the same length
    if len(game) != len(guess):
        raise ValueError("Game and guess lists must be of the same length.")

    return [abs(x - y) for x, y in zip(game, guess)]

def Strongest_Extension(class_name, extensions):
    strong = extensions[0]
    my_val = len([x for x in strong if x.isalpha() and x.isupper()]) - len([x for x in strong if x.isalpha() and x.islower()])
    for s in extensions:
        val = len([x for x in s if x.isalpha() and x.isupper()]) - len([x for x in s if x.isalpha() and x.islower()])
        if val > my_val:
            strong = s
            my_val = val

    ans = class_name + "." + strong
    return ans

